import java.util.Scanner;

public class DigitDp {
    static int[] digits;
    static int targetSum;
    static int numDigits;
    static int[][][] memo;

    public static int digitDp(int n, int target) {
        if (n <= 0 || target <= 0) return 0;

        targetSum = target;
        String s = Integer.toString(n);
        numDigits = s.length();
        digits = new int[numDigits];
        for (int i = 0; i < numDigits; i++) {
            digits[i] = s.charAt(i) - '0';
        }

        int maxSum = 9 * numDigits;
        if (target > maxSum) return 0;

        memo = new int[numDigits][maxSum + 1][2];
        for (int[][] a : memo)
            for (int[] b : a)
                java.util.Arrays.fill(b, -1);

        return solve(0, 0, 1);
    }

    private static int solve(int pos, int currentSum, int tight) {
        if (currentSum > targetSum) return 0;
        if (pos == numDigits) {
            return currentSum == targetSum ? 1 : 0;
        }

        if (memo[pos][currentSum][tight] != -1) {
            return memo[pos][currentSum][tight];
        }

        int limit = tight == 1 ? digits[pos] : 9;
        int result = 0;
        for (int d = 0; d <= limit; d++) {
            result += solve(pos + 1, currentSum + d, (tight == 1 && d == limit) ? 1 : 0);
        }

        memo[pos][currentSum][tight] = result;
        return result;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int target = sc.nextInt();
        System.out.println(digitDp(n, target));
    }
}

fun digitDp(n: Int, targetSum: Int): Int {
    if (n <= 0) return 0

    val s = n.toString()
    val digits = s.map { it - '0' }
    val numDigits = digits.size
    val maxSum = 9 * numDigits

    if (targetSum > maxSum) return 0

    val memo = Array(numDigits) { Array(maxSum + 1) { IntArray(2) { -1 } } }

    fun solve(pos: Int, currentSum: Int, tight: Int): Int {
        if (currentSum > targetSum) return 0
        if (pos == numDigits) {
            return if (currentSum == targetSum) 1 else 0
        }
        if (memo[pos][currentSum][tight] != -1) {
            return memo[pos][currentSum][tight]
        }

        val limit = if (tight == 1) digits[pos] else 9
        var result = 0
        for (d in 0..limit) {
            val newTight = if (tight == 1 && d == limit) 1 else 0
            result += solve(pos + 1, currentSum + d, newTight)
        }

        memo[pos][currentSum][tight] = result
        return result
    }

    val count = solve(0, 0, 1)
    return if (targetSum == 0) count - 1 else count
}

use std::collections::HashMap;
use std::io::{self, Read};

fn digit_dp(n: i64, target_sum: i32) -> i64 {
    if n <= 0 {
        return 0;
    }

    let s = n.to_string();
    let digits: Vec<i32> = s.chars().map(|c| c as i32 - '0' as i32).collect();
    let num_digits = digits.len();

    let mut memo: HashMap<(usize, i32, bool), i64> = HashMap::new();

    fn solve(
        pos: usize,
        current_sum: i32,
        tight: bool,
        digits: &[i32],
        num_digits: usize,
        target_sum: i32,
        memo: &mut HashMap<(usize, i32, bool), i64>,
    ) -> i64 {
        if current_sum > target_sum {
            return 0;
        }
        if pos == num_digits {
            return if current_sum == target_sum { 1 } else { 0 };
        }

        let key = (pos, current_sum, tight);
        if let Some(&val) = memo.get(&key) {
            return val;
        }

        let limit = if tight { digits[pos] } else { 9 };
        let mut result: i64 = 0;
        for d in 0..=limit {
            result += solve(
                pos + 1,
                current_sum + d,
                tight && d == limit,
                digits,
                num_digits,
                target_sum,
                memo,
            );
        }

        memo.insert(key, result);
        result
    }

    solve(0, 0, true, &digits, num_digits, target_sum, &mut memo)
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_whitespace();
    let n: i64 = iter.next().unwrap().parse().unwrap();
    let target: i32 = iter.next().unwrap().parse().unwrap();
    println!("{}", digit_dp(n, target));
}

